const body = $input.first().json.body || $input.first().json;
const client = body.client || {};
const messages = body.messages || [];
const followUps = body.followUps || [];

const recentMessages = messages.slice(0, 5).map(m => `- [${m.direction}] ${m.message_type}: ${m.summary || m.message}`).join('\n');
const pendingFollowUps = followUps.filter(f => f.status !== 'Completed').map(f => `- ${f.title} (due ${f.due_date})`).join('\n');

const prompt = `You are an expert business communication assistant helping a solo service provider reach out to a client.

Client details:
- Name: ${client.name}
- Business type: ${client.business_type || 'Not specified'}
- Tags: ${(client.tags || []).join(', ') || 'None'}
- Status: ${client.status}
- Notes: ${client.notes || 'None'}
- Last contacted: ${client.last_contact_date || 'Never'}

Recent conversation history:
${recentMessages || 'No previous conversations'}

Pending follow-ups:
${pendingFollowUps || 'None'}

Write a warm, professional, and personalised WhatsApp message from the service provider to this client. The message should:
1. Reference the client's specific business context and notes
2. Be conversational and friendly (not salesy)
3. Include a clear but gentle call-to-action
4. Be under 150 words
5. Feel human — not like a template

Return ONLY the message text, no subject lines or extra formatting.`;

return [{ json: { prompt, client_name: client.name } }];

const draft = $input.first().json.message?.content || $input.first().json.content || '';
return [{
  json: {
    draft_text: draft.trim(),
    channel: 'WhatsApp',
    status: 'Draft'
  }
}];
